---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import Accordion from '../components/Accordion.astro';
import RideRequestForm from '../components/RideRequestForm.astro';
import { getVisitPage, urlForImage, portableTextToHtml } from '../lib/sanity';

const title = 'Plan Your Visit | First Ithaca Chinese Christian Church';
const description =
  'Everything you need to know for your first Sunday with us — service times, directions, parking, and what to expect.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let visitPage: Awaited<ReturnType<typeof getVisitPage>> = null;

try {
  visitPage = await getVisitPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackSchedule = [
  {
    label: 'Sunday Gathering',
    time: '9:45 AM',
    description:
      'Worship service with singing, prayer, and a message from Scripture',
  },
  {
    label: 'Sunday School',
    time: '11:15 AM',
    description:
      'Age-specific classes for children, youth, and adults',
  },
];

const fallbackWhatToExpectHtml = `
<p>Whether it's your first time at church or you've been part of a community before, you're welcome here just as you are.</p>
<p><strong>Dress code:</strong> Come as you are — most people dress casually. You'll see everything from jeans to button-downs.</p>
<p><strong>What happens on Sunday:</strong> Our gathering includes worship through singing, prayer, Scripture reading, and a sermon. Services are primarily in English with occasional bilingual elements.</p>
<p><strong>Kids are welcome:</strong> Children are always welcome in the main service. We also offer age-appropriate Sunday School classes after the gathering.</p>
<p><strong>How long is the service?</strong> The Sunday gathering typically lasts about 75 minutes.</p>
`;

const fallbackTransportationHtml = `
<p><strong>Address:</strong> 429 Mitchell Street, Ithaca, NY 14850</p>
<p><strong>Parking:</strong> Free parking is available in our lot adjacent to the building. Street parking is also available on Mitchell Street and nearby side streets.</p>
<p><strong>Near Cornell:</strong> We're a short drive from Cornell University's campus. If you're a student without a car, we'd be happy to help arrange a ride — just ask!</p>
<p><strong>Public transit:</strong> TCAT bus routes serve the area. Check <a href="https://tcatbus.com">tcatbus.com</a> for schedules.</p>
`;

const fallbackFaqItems = [
  {
    question: 'What should I wear?',
    answer:
      `There's no dress code — come as you are. Most people dress casually.`,
  },
  {
    question: 'Are children welcome?',
    answer:
      'Absolutely! Children are welcome in the main service, and we offer Sunday School classes for different age groups after the gathering.',
  },
  {
    question: 'What language is the service in?',
    answer:
      'Our services are primarily in English with occasional bilingual (English/Chinese) elements. Everyone is welcome regardless of language background.',
  },
  {
    question: 'Is there parking available?',
    answer:
      'Yes — free parking is available in our lot next to the building, and street parking is available nearby.',
  },
  {
    question: 'How long is the service?',
    answer:
      'The Sunday gathering typically lasts about 75 minutes. Sunday School classes follow at 11:15 AM and run for about 45 minutes.',
  },
  {
    question: 'How can I get connected during the week?',
    answer:
      `We'd love to help you find community! After the service, stop by the welcome table to learn about small groups, Bible studies, and other ways to connect. You can also reach out through our contact page.`,
  },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heroImage = visitPage?.heroImage
  ? urlForImage(visitPage.heroImage, { width: 1600 })
  : '/images/hero-placeholder.svg';
const heroTitle = visitPage?.heroTitle || 'Plan Your Visit';
const heroSubtitle =
  visitPage?.heroSubtitle ||
  'Everything you need to know for your first Sunday with us';

const schedule =
  visitPage?.schedule && visitPage.schedule.length > 0
    ? visitPage.schedule
    : fallbackSchedule;

const whatToExpectHtml =
  visitPage?.whatToExpect && visitPage.whatToExpect.length > 0
    ? portableTextToHtml(visitPage.whatToExpect)
    : fallbackWhatToExpectHtml;

const transportationHtml =
  visitPage?.transportation && visitPage.transportation.length > 0
    ? portableTextToHtml(visitPage.transportation)
    : fallbackTransportationHtml;

const faqItems =
  visitPage?.faqItems && visitPage.faqItems.length > 0
    ? visitPage.faqItems
    : fallbackFaqItems;

// Map FAQ items to Accordion's expected shape
const accordionItems = faqItems.map((item) => ({
  title: item.question,
  content: item.answer,
}));

const showRideRequest = visitPage?.rideRequestEnabled !== false;
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title={heroTitle}
      subtitle={heroSubtitle}
      backgroundImage={heroImage}
    />

    <!-- Schedule -->
    <section class="schedule" aria-label="Sunday Schedule">
      <div class="schedule__inner">
        <h2 class="section-heading">Sunday Schedule</h2>
        <div class="schedule__grid">
          {schedule.map((item) => (
            <div class="schedule__card">
              <span class="schedule__time">{item.time}</span>
              <h3 class="schedule__label">{item.label}</h3>
              {item.description && (
                <p class="schedule__desc">{item.description}</p>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>

    <!-- What to Expect -->
    <section class="expect" aria-label="What to Expect">
      <div class="expect__inner">
        <h2 class="section-heading">What to Expect</h2>
        <div class="expect__body" set:html={whatToExpectHtml} />
      </div>
    </section>

    <!-- Transportation & Directions -->
    <section class="directions" aria-label="Transportation and Directions">
      <div class="directions__inner">
        <h2 class="section-heading">Getting Here</h2>
        <div class="directions__columns">
          <div class="directions__body" set:html={transportationHtml} />
          <div class="directions__map">
            <iframe
              title="Church location on Google Maps"
              src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2942.8!2d-76.5005!3d42.4440!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2z429+Mitchell+Street%2C+Ithaca%2C+NY+14850!5e0!3m2!1sen!2sus!4v1"
              width="100%"
              height="300"
              style="border:0; border-radius: var(--radius-md);"
              allowfullscreen=""
              loading="lazy"
              referrerpolicy="no-referrer-when-downgrade"
            ></iframe>
          </div>
        </div>
      </div>
    </section>

    <!-- FAQ -->
    <section class="faq" aria-label="Frequently Asked Questions">
      <div class="faq__inner">
        <h2 class="section-heading">Frequently Asked Questions</h2>
        <Accordion items={accordionItems} />
      </div>
    </section>

    <!-- Ride Request -->
    {showRideRequest && (
      <section class="ride-request" aria-label="Request a Ride">
        <div class="ride-request__inner">
          <h2 class="section-heading">Need a Ride?</h2>
          <p class="ride-request__intro">
            Don't have a car? No problem — we'd love to pick you up! Fill out the form below and someone from our team will reach out to arrange a ride.
          </p>
          <RideRequestForm />
        </div>
      </section>
    )}
  </main>
</BaseLayout>

<!-- Cloudflare Turnstile — loaded async for form spam protection -->
<script is:inline src="https://challenges.cloudflare.com/turnstile/v0/api.js" async defer></script>

<style>
  /* ---------- Shared ---------- */
  .section-heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-10);
  }

  /* ---------- Schedule ---------- */
  .schedule {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .schedule__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .schedule__grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(16rem, 1fr));
    gap: var(--space-8);
  }

  .schedule__card {
    background-color: var(--color-stone);
    border-radius: var(--radius-md);
    padding: var(--space-8) var(--space-6);
    text-align: center;
  }

  .schedule__time {
    display: block;
    font-family: var(--font-heading);
    font-size: var(--text-2xl);
    font-weight: 700;
    color: var(--color-terracotta);
    margin-block-end: var(--space-2);
  }

  .schedule__label {
    font-family: var(--font-heading);
    font-size: var(--text-xl);
    color: var(--color-ink);
    margin-block-end: var(--space-3);
  }

  .schedule__desc {
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }

  /* ---------- What to Expect ---------- */
  .expect {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .expect__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .expect__body {
    max-width: 48rem;
    margin-inline: auto;
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }

  .expect__body :global(p) {
    margin-block-end: var(--space-4);
  }

  .expect__body :global(p:last-child) {
    margin-block-end: 0;
  }

  .expect__body :global(strong) {
    color: var(--color-ink);
  }

  /* ---------- Directions ---------- */
  .directions {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .directions__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .directions__columns {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--space-10);
    align-items: start;
  }

  .directions__body {
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }

  .directions__body :global(p) {
    margin-block-end: var(--space-4);
  }

  .directions__body :global(p:last-child) {
    margin-block-end: 0;
  }

  .directions__body :global(strong) {
    color: var(--color-ink);
  }

  .directions__body :global(a) {
    color: var(--color-terracotta);
    text-decoration: underline;
  }

  .directions__map {
    border-radius: var(--radius-md);
    overflow: hidden;
  }

  .directions__map iframe {
    display: block;
  }

  /* ---------- FAQ ---------- */
  .faq {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .faq__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  /* ---------- Ride Request ---------- */
  .ride-request {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .ride-request__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .ride-request__intro {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    text-align: center;
    max-width: 36rem;
    margin-inline: auto;
    margin-block-end: var(--space-10);
  }

  /* ---------- Responsive ---------- */
  @media (max-width: 768px) {
    .section-heading {
      font-size: var(--text-2xl);
    }

    .directions__columns {
      grid-template-columns: 1fr;
    }

    .schedule__grid {
      grid-template-columns: 1fr;
    }
  }
</style>

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import { getAboutPage, portableTextToHtml, urlForImage } from '../../lib/sanity';

const title = 'Who We Are | FICCC';
const description =
  'Learn about First Ithaca Chinese Christian Church — our history, mission, and community.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let aboutPage: Awaited<ReturnType<typeof getAboutPage>> = null;

try {
  aboutPage = await getAboutPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackHeading = 'Who We Are';
const fallbackBody = `
<p>First Ithaca Chinese Christian Church (FICCC) was founded in 1968 by a small group of Chinese graduate students and scholars at Cornell University who longed for a Christ-centered community where they could worship in their heart language while welcoming the broader Ithaca community.</p>
<p>Over the decades the church has grown into a multigenerational, multicultural congregation that bridges Chinese heritage and American life. We gather every Sunday at 429 Mitchell Street for worship, teaching, and fellowship — in English and Mandarin — serving students, families, and neighbors throughout the Finger Lakes region.</p>
<p>Our mission is to glorify God by making disciples of Jesus Christ who love God wholeheartedly, love one another sacrificially, and reach out to the world with the Gospel. We believe the local church is God's primary instrument for advancing His kingdom, and we are committed to equipping every member for a life of faithful service.</p>
<p>Whether you are a longtime resident of Ithaca, a visiting scholar, or a student far from home, there is a place for you at FICCC. We invite you to come as you are and experience the warmth of Christ's love in community.</p>
`.trim();

// ---------- Resolved data (CMS ▸ fallback) ----------
const heading = aboutPage?.whoWeAreHeading || fallbackHeading;
const bodyHtml = aboutPage?.whoWeAreBody?.length
  ? portableTextToHtml(aboutPage.whoWeAreBody)
  : fallbackBody;
const imageUrl = aboutPage?.whoWeAreImage
  ? urlForImage(aboutPage.whoWeAreImage, { width: 800 })
  : '';
---

<BaseLayout title={title} description={description}>
  <main class="about">
    <section class="about__hero" aria-label="Who We Are">
      <div class="about__inner">
        <h1 class="about__heading">{heading}</h1>
        <div class="about__content">
          <div class="about__body" set:html={bodyHtml} />
          {imageUrl && (
            <div class="about__image-wrap">
              <img
                class="about__image"
                src={imageUrl}
                alt={heading}
                loading="lazy"
                width="800"
                height="533"
              />
            </div>
          )}
        </div>
      </div>
    </section>
  </main>
</BaseLayout>

<style>
  .about {
    padding-block: var(--space-16);
  }

  .about__inner {
    max-width: var(--max-width);
    margin-inline: auto;
    padding-inline: var(--space-6);
  }

  .about__heading {
    font-family: var(--font-heading);
    font-size: var(--text-4xl);
    color: var(--color-ink);
    margin-block-end: var(--space-8);
  }

  .about__content {
    display: grid;
    grid-template-columns: 1fr;
    gap: var(--space-10);
  }

  .about__body {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    max-width: 48rem;
  }

  .about__body :global(p) {
    margin-block-end: var(--space-4);
  }

  .about__body :global(p:last-child) {
    margin-block-end: 0;
  }

  .about__body :global(a) {
    color: var(--color-terracotta);
    text-decoration: underline;
  }

  .about__image-wrap {
    border-radius: var(--radius-lg, 0.75rem);
    overflow: hidden;
  }

  .about__image {
    width: 100%;
    height: auto;
    display: block;
    object-fit: cover;
  }

  @media (min-width: 768px) {
    .about__content {
      grid-template-columns: 3fr 2fr;
      align-items: start;
    }
  }

  @media (max-width: 767px) {
    .about__heading {
      font-size: var(--text-3xl);
    }

    .about__body {
      font-size: var(--text-base);
    }
  }
</style>

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import Accordion from '../../components/Accordion.astro';
import { getAboutPage, portableTextToHtml } from '../../lib/sanity';

const title = 'What We Believe | FICCC';
const description =
  'The core doctrinal beliefs of First Ithaca Chinese Christian Church.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let aboutPage: Awaited<ReturnType<typeof getAboutPage>> = null;

try {
  aboutPage = await getAboutPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback beliefs ----------
const fallbackBeliefs = [
  {
    title: 'The Scriptures',
    content:
      '<p>We believe the Bible is the inspired, infallible, and authoritative Word of God. It is the supreme standard for all faith, life, and conduct, given by the Holy Spirit through human authors without error in the original manuscripts.</p>',
  },
  {
    title: 'God',
    content:
      '<p>We believe in one God, eternally existing in three persons — Father, Son, and Holy Spirit — each fully God, each personally distinct, yet one in essence and purpose.</p>',
  },
  {
    title: 'Jesus Christ',
    content:
      '<p>We believe in the deity of our Lord Jesus Christ, His virgin birth, His sinless life, His miracles, His atoning death on the cross, His bodily resurrection, His ascension to the right hand of the Father, and His personal return in power and glory.</p>',
  },
  {
    title: 'The Holy Spirit',
    content:
      '<p>We believe the Holy Spirit convicts the world of sin, regenerates believers, indwells them from the moment of salvation, and empowers them for godly living and service. He illuminates Scripture and distributes spiritual gifts for the building up of the Church.</p>',
  },
  {
    title: 'Salvation',
    content:
      '<p>We believe that all people are sinners by nature and by choice and are therefore under condemnation. We believe that salvation is a gift of God received by faith alone in Jesus Christ alone. Those who repent and believe are justified, adopted into God\'s family, and sealed by the Holy Spirit.</p>',
  },
  {
    title: 'The Church',
    content:
      '<p>We believe in the universal Church, a living spiritual body of which Christ is the Head and of which all regenerated people are members. We believe that the local church is a community of baptized believers, organized for worship, instruction, fellowship, and evangelism, observing the ordinances of baptism and the Lord\'s Supper.</p>',
  },
  {
    title: 'The Christian Life',
    content:
      '<p>We believe that God\'s justifying grace must not be separated from His sanctifying power and purpose. God commands us to love Him supremely and to love others sacrificially, and to live out our faith through prayer, service, generosity, and obedience to His Word.</p>',
  },
  {
    title: 'Eternity',
    content:
      '<p>We believe in the personal, visible return of the Lord Jesus Christ, the resurrection of the body, the final judgment, the eternal blessedness of the righteous, and the endless suffering of the wicked. We look forward to the new heavens and new earth in which righteousness dwells.</p>',
  },
];

// ---------- Resolved beliefs (CMS ▸ fallback) ----------
const beliefs =
  aboutPage?.beliefs && aboutPage.beliefs.length > 0
    ? aboutPage.beliefs.map((b) => ({
        title: b.title,
        content: b.content?.length
          ? portableTextToHtml(b.content)
          : `<p>${b.title}</p>`,
      }))
    : fallbackBeliefs;
---

<BaseLayout title={title} description={description}>
  <main class="beliefs">
    <section class="beliefs__hero" aria-label="What We Believe">
      <div class="beliefs__inner">
        <h1 class="beliefs__heading">What We Believe</h1>
        <p class="beliefs__intro">
          These core convictions, rooted in Scripture, shape who we are as a
          church and how we live together as followers of Jesus Christ.
        </p>
        <Accordion items={beliefs} />
      </div>
    </section>
  </main>
</BaseLayout>

<style>
  .beliefs {
    padding-block: var(--space-16);
  }

  .beliefs__inner {
    max-width: var(--max-width);
    margin-inline: auto;
    padding-inline: var(--space-6);
  }

  .beliefs__heading {
    font-family: var(--font-heading);
    font-size: var(--text-4xl);
    color: var(--color-ink);
    margin-block-end: var(--space-4);
  }

  .beliefs__intro {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    max-width: 48rem;
    margin-block-end: var(--space-10);
  }

  @media (max-width: 767px) {
    .beliefs__heading {
      font-size: var(--text-3xl);
    }

    .beliefs__intro {
      font-size: var(--text-base);
    }
  }
</style>

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import StaffCard from '../../components/StaffCard.astro';
import { getStaff, urlForImage } from '../../lib/sanity';
import type { Person } from '../../lib/sanity';

const title = 'Our Staff | FICCC';
const description =
  'Meet the pastoral and ministry staff at First Ithaca Chinese Christian Church.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let staff: Person[] = [];

try {
  staff = await getStaff('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Hardcoded fallbacks ----------
const fallbackStaff: Pick<Person, 'name' | 'role'>[] = [
  { name: 'Rev. David Chen', role: 'Senior Pastor' },
  { name: 'Pastor Grace Liu', role: 'Associate Pastor' },
  { name: 'Elder James Wang', role: 'Director of Worship' },
  { name: 'Sarah Thompson', role: 'Youth Ministry Director' },
];

const hasStaff = staff.length > 0;
---

<BaseLayout title={title} description={description}>
  <main class="staff-page">
    <section class="staff-page__inner" aria-label="Our Staff">
      <h1 class="staff-page__heading">Our Staff</h1>
      <p class="staff-page__intro">
        The pastoral team and ministry staff at FICCC serve with a shared commitment
        to faithfully teach God's Word, shepherd His people, and equip the church for
        mission in Ithaca and beyond.
      </p>

      <div class="staff-page__grid">
        {hasStaff
          ? staff.map((person) => (
              <StaffCard
                name={person.name}
                role={person.role}
                photoUrl={person.photo ? urlForImage(person.photo, { width: 400 }) : undefined}
              />
            ))
          : fallbackStaff.map((person) => (
              <StaffCard name={person.name} role={person.role} />
            ))
        }
      </div>
    </section>
  </main>
</BaseLayout>

<style>
  .staff-page {
    padding-block: var(--space-16);
  }

  .staff-page__inner {
    max-width: var(--max-width);
    margin-inline: auto;
    padding-inline: var(--space-6);
  }

  .staff-page__heading {
    font-family: var(--font-heading);
    font-size: var(--text-4xl);
    color: var(--color-ink);
    margin-block-end: var(--space-4);
  }

  .staff-page__intro {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    max-width: 48rem;
    margin-block-end: var(--space-12);
  }

  .staff-page__grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: var(--space-8);
  }

  @media (min-width: 640px) {
    .staff-page__grid {
      grid-template-columns: repeat(2, 1fr);
    }
  }

  @media (min-width: 1024px) {
    .staff-page__grid {
      grid-template-columns: repeat(3, 1fr);
    }
  }

  @media (max-width: 639px) {
    .staff-page__heading {
      font-size: var(--text-3xl);
    }

    .staff-page__intro {
      font-size: var(--text-base);
    }
  }
</style>

---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import ContactForm from '../components/ContactForm.astro';
import PrayerRequestForm from '../components/PrayerRequestForm.astro';
import RideRequestForm from '../components/RideRequestForm.astro';
import ConnectForm from '../components/ConnectForm.astro';

const title = 'Contact | First Ithaca Chinese Christian Church';
const description =
  'Get in touch with First Ithaca Chinese Christian Church. Send a message, submit a prayer request, request a ride, or connect with us.';

const siteKey = import.meta.env.PUBLIC_TURNSTILE_SITE_KEY ?? '';
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title="Contact Us"
